<?php
global $post;
$is_single_blog = is_single() && $post->post_type == 'post';
$is_blog_archive = ((is_category() || is_tag() || is_archive())&& $post->post_type == 'post') || is_page('blog');
$is_blog_page = $is_single_blog || $is_blog_archive;
$menu_location = $is_blog_page ? 'blog' : 'header';
$header_menu_items = get_option('ez_mega_menu_' . $menu_location, []);

if ($is_blog_page && empty($header_menu_items)) {
    $header_menu_items = get_option('ez_mega_menu_header', []);
}

if (empty($header_menu_items)) {
    return;
}
?>

<!-- Menu Content -->
<div class="flex-1 submenu-container mt-16">
    <!-- Main Menu Items -->
    <nav id="main-menu" class="py-2 flex flex-col justify-between h-full submenu-item">
        <div>
            <?php
            $submenu_index = 0;
            foreach ($header_menu_items as $menu_item):
                // بررسی visibility - این فایل برای موبایل است
                $item_visibility = $menu_item['item_visibility'] ?? 'both';
                if ($item_visibility === 'none') continue;
                if ($item_visibility === 'desktop') continue; // فقط desktop را نمایش نمی‌دهیم

                // بررسی فرزندان
                $has_children = !empty($menu_item['children']);
                $submenu_id = 'submenu-' . $submenu_index;
            ?>

                <?php if ($has_children): ?>
                    <!-- Menu Item with Children -->
                    <a href="#"
                        class="menu-item flex items-center justify-between px-4 py-3 text-gray-800 hover:bg-gray-50 transition-colors border-b border-gray-100"
                        data-submenu="<?php echo esc_attr($submenu_id); ?>">
                        <span class="font-medium"><?php echo esc_html($menu_item['title']); ?></span>
                        <svg class="w-4 h-4 text-gray-400 mx-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 19l-7-7 7-7"></path>
                        </svg>
                    </a>
                <?php else: ?>
                    <!-- Simple Menu Item -->
                    <a href="<?php echo esc_url($menu_item['url']); ?>"
                        class="block px-4 py-3 text-gray-800 hover:bg-gray-50 transition-colors border-b border-gray-100">
                        <?php echo esc_html($menu_item['title']); ?>
                    </a>
                <?php endif; ?>

            <?php
                if ($has_children) $submenu_index++;
            endforeach;
            ?>
