    <!-- Submenus -->
    <?php
    $submenu_index = 0;
    foreach ($header_menu_items as $menu_item):
        // بررسی visibility - این فایل برای موبایل است
        $item_visibility = $menu_item['item_visibility'] ?? 'both';
        if ($item_visibility === 'none') continue;
        if ($item_visibility === 'desktop') continue; // فقط desktop را نمایش نمی‌دهیم

        $has_children = !empty($menu_item['children']);
        if (!$has_children) continue;

        $submenu_id = 'submenu-' . $submenu_index;
    ?>
        <!-- Submenu for: <?php echo esc_html($menu_item['title']); ?> -->
        <nav id="<?php echo esc_attr($submenu_id); ?>-submenu" class="py-2 hidden submenu-item">
            <!-- Submenu Header -->
            <div class="flex items-center bg-[#F1F5F9] rounded-lg h-9 justify-center mx-8 gap-x-3 mt-3">
                <button type="button" class="back-to-main-menu flex items-center gap-2 text-gray-600 hover:text-gray-800 transition-colors">
                    <svg xmlns="http://www.w3.org/2000/svg" width="9" height="14" viewBox="0 0 9 14" fill="none">
                        <path d="M2 2L7 7L2 12" stroke="#90A1B9" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" />
                    </svg>
                    <span class="text-sm text-[#09192D]">بازگشت به منو اصلی</span>
                </button>
            </div>

            <!-- Submenu Title -->
            <div class="px-4 py-3">
                <h3 class="text-2xl font-bold text-[#09192D]"><?php echo esc_html($menu_item['title']); ?></h3>
                <hr class="mt-4">
            </div>

            <!-- Submenu Items -->
            <div class="px-2 max-h-[calc(100vh-200px)] overflow-y-auto scrollbar-hide">
                <?php foreach ($menu_item['children'] as $child):
                    // بررسی visibility فرزند - این فایل برای موبایل است
                    $child_visibility = $child['item_visibility'] ?? 'both';
                    if ($child_visibility === 'none') continue;
                    if ($child_visibility === 'desktop') continue; // فقط desktop را نمایش نمی‌دهیم
                ?>
                    <a href="<?php echo esc_url($child['url']); ?>"
                        class="block px-2 py-3 text-gray-800 hover:bg-gray-50 transition-colors rounded-lg">
                        <?php echo esc_html($child['title']); ?>
                    </a>
                <?php endforeach; ?>
            </div>
        </nav>
    <?php
        $submenu_index++;
    endforeach;
